sealed class PlatformAdapterException: kotlin.Exception() {

    class Cancelled(
        ) : PlatformAdapterException() {
        override val message
            get() = ""
    }

    class Invalidated(
        ) : PlatformAdapterException() {
        override val message
            get() = ""
    }

    class Failure(

        val `details`: kotlin.String
        ) : PlatformAdapterException() {
        override val message
            get() = "details=${ `details` }"
    }

    class Unexpected(
        ) : PlatformAdapterException() {
        override val message
            get() = ""
    }





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<PlatformAdapterException> {
        override fun lift(error_buf: RustBuffer.ByValue): PlatformAdapterException = FfiConverterTypePlatformAdapterError.lift(error_buf)
    }


}

/**
 * @suppress
 */
public object FfiConverterTypePlatformAdapterError : FfiConverterRustBuffer<PlatformAdapterException> {
    override fun read(buf: ByteBuffer): PlatformAdapterException {


        return when(buf.getInt()) {
            1 -> PlatformAdapterException.Cancelled()
            2 -> PlatformAdapterException.Invalidated()
            3 -> PlatformAdapterException.Failure(
                FfiConverterString.read(buf),
                )
            4 -> PlatformAdapterException.Unexpected()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: PlatformAdapterException): ULong {
        return when(value) {
            is PlatformAdapterException.Cancelled -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is PlatformAdapterException.Invalidated -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is PlatformAdapterException.Failure -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is PlatformAdapterException.Unexpected -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: PlatformAdapterException, buf: ByteBuffer) {
        when(value) {
            is PlatformAdapterException.Cancelled -> {
                buf.putInt(1)
                Unit
            }
            is PlatformAdapterException.Invalidated -> {
                buf.putInt(2)
                Unit
            }
            is PlatformAdapterException.Failure -> {
                buf.putInt(3)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is PlatformAdapterException.Unexpected -> {
                buf.putInt(4)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




