    class KdfForbidden(

        val `algorithm`: kotlin.String,

        val `resource`: kotlin.String,

        val `observed`: kotlin.ULong
        ) : VaultKernException() {
        override val message
            get() = "algorithm=${ `algorithm` }, resource=${ `resource` }, observed=${ `observed` }"
    }





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<VaultKernException> {
        override fun lift(error_buf: RustBuffer.ByValue): VaultKernException = FfiConverterTypeVaultKernError.lift(error_buf)
    }


}

/**
